import json
businesses_2018 = locals()['var_functions.query_db:14']

def has_parking_or_bike_parking(business):
    """Check if a business offers business parking or bike parking"""
    attributes = business.get('attributes')
    if not attributes or attributes == 'None':
        return False

    # Check for BusinessParking
    has_business_parking = False
    if 'BusinessParking' in attributes:
        bp = attributes['BusinessParking']
        if bp and bp != 'None':
            # Try to parse the BusinessParking dict string
            try:
                # It's a string representation of a dict like "{'garage': False, 'street': True}"
                # For now, just check if it's not False/None/empty
                has_business_parking = True
            except:
                pass

    # Check for BikeParking
    has_bike_parking = False
    if 'BikeParking' in attributes:
        bike = attributes['BikeParking']
        # Check if it's True (could be string 'True' or boolean True)
        if bike == 'True' or bike == True:
            has_bike_parking = True

    return has_business_parking or has_bike_parking

# Filter businesses
count = 0
businesses_with_parking = []
for business in businesses_2018:
    if has_parking_or_bike_parking(business):
        count += 1
        businesses_with_parking.append({
            'business_id': business['business_id'],
            'name': business['name'],
            'attributes': business.get('attributes')
        })

print('__RESULT__:')
print(json.dumps({
    'count': count,
    'businesses': businesses_with_parking
}))

